'use client'

import { useEffect, useRef, useState } from 'react'
import { ExternalLink, Github } from 'lucide-react'

const PROJECTS = [
  {
    title: 'Internet Banking Platform',
    description:
      'Built a full-featured internet banking interface for FCMB UK — account management, transactions, and compliance workflows serving thousands of daily users.',
    tools: ['React', 'Next.js', 'TypeScript', 'REST APIs', 'Jest'],
    color: 'bg-accent/8',
  },
  {
    title: 'Component Design System',
    description:
      'Created a shared component library with 50+ accessible, themeable components, Storybook documentation, and automated visual regression testing.',
    tools: ['React', 'Tailwind CSS', 'Storybook', 'TypeScript', 'npm'],
    color: 'bg-secondary/8',
  },
  {
    title: 'Real-Time Analytics Dashboard',
    description:
      'Developed an analytics dashboard with live-updating charts, filterable data tables, and exportable reports for internal stakeholders.',
    tools: ['React', 'Recharts', 'Zustand', 'WebSockets', 'Node.js'],
    color: 'bg-accent/8',
  },
  {
    title: 'Cross-Platform Mobile App',
    description:
      'Shipped a React Native app with offline-first architecture, background sync, push notifications, and biometric auth across iOS and Android.',
    tools: ['React Native', 'Firebase', 'Redux', 'TypeScript', 'Expo'],
    color: 'bg-secondary/8',
  },
] as const

export default function Projects() {
  const [isVisible, setIsVisible] = useState(false)
  const ref = useRef<HTMLElement>(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) setIsVisible(true)
      },
      { threshold: 0.1 }
    )

    if (ref.current) observer.observe(ref.current)
    return () => observer.disconnect()
  }, [])

  return (
    <section id="projects" ref={ref} className="py-24 px-6">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-14">
          <p className="text-accent text-sm font-mono tracking-widest uppercase mb-3">
            Work
          </p>
          <h2 className="text-3xl md:text-4xl font-bold text-foreground">
            Featured Projects
          </h2>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          {PROJECTS.map((project, idx) => (
            <div
              key={project.title}
              className="group rounded-xl overflow-hidden border border-border bg-card hover:border-accent/40 hover:shadow-md transition-all duration-300 hover:-translate-y-0.5"
              style={{
                transitionDelay: isVisible ? `${idx * 80}ms` : '0ms',
                opacity: isVisible ? 1 : 0,
                transform: isVisible ? 'translateY(0)' : 'translateY(20px)',
              }}
            >
              <div className={`h-44 ${project.color} flex items-center justify-center`}>
                <div className="flex gap-3 opacity-0 group-hover:opacity-100 transition-opacity duration-200">
                  <button
                    className="p-2.5 rounded-lg bg-white shadow-md text-foreground hover:text-accent transition-colors"
                    aria-label={`View ${project.title} live`}
                  >
                    <ExternalLink size={18} />
                  </button>
                  <button
                    className="p-2.5 rounded-lg bg-white shadow-md text-foreground hover:text-accent transition-colors"
                    aria-label={`View ${project.title} source`}
                  >
                    <Github size={18} />
                  </button>
                </div>
              </div>

              <div className="p-6">
                <h3 className="text-lg font-bold text-foreground mb-2 group-hover:text-accent transition-colors">
                  {project.title}
                </h3>
                <p className="text-muted-foreground text-sm mb-4 leading-relaxed">
                  {project.description}
                </p>

                <div className="flex flex-wrap gap-1.5">
                  {project.tools.map((tool) => (
                    <span
                      key={tool}
                      className="px-2.5 py-1 text-xs rounded-md bg-muted text-muted-foreground font-mono"
                    >
                      {tool}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
